func runDuration(run entity.JobRun) string {
	if run.EndedAt == nil {
		if run.Status == entity.RunStatusRunning {
			return "running…"
		}
		return "—"
	}
	d := run.EndedAt.Sub(run.StartedAt)
	if d < time.Second {
		return fmt.Sprintf("%dms", d.Milliseconds())
	}
	return fmt.Sprintf("%.1fs", d.Seconds())
}

func scheduleLabel(j *entity.Job) string {
	if j.Schedule == "" {
		return "—"
	}
	return j.Schedule
}

func lastRunLabel(runs []entity.JobRun) string {
	if len(runs) == 0 {
		return "—"
	}
	last := runs[0]
	return last.StartedAt.Format("Jan 2 15:04")
}

